import{_ as a,I as r,c as n,o as i,a5 as d,J as s,j as e}from"./chunks/framework.Dtwt352Q.js";const b=JSON.parse('{"title":"OpenCode Zen","description":"Curated model service tested and validated by the OpenCode team","frontmatter":{"title":"OpenCode Zen","description":"Curated model service tested and validated by the OpenCode team"},"headers":[],"relativePath":"en/appendix/zen.md","filePath":"en/appendix/zen.md","lastUpdated":1772014034000}'),l={name:"en/appendix/zen.md"};function c(p,t,h,m,u,g){const o=r("AdInArticle");return i(),n("div",null,[t[0]||(t[0]=d('<h1 id="opencode-zen" tabindex="-1">OpenCode Zen <a class="header-anchor" href="#opencode-zen" aria-label="Permalink to “OpenCode Zen”">​</a></h1><p>OpenCode Zen is a curated model service tested and validated by the OpenCode team.</p><blockquote><p>OpenCode Zen is currently in Beta.</p></blockquote><p>Zen works like any other provider in OpenCode. You log in to OpenCode Zen to get an API key. It&#39;s <strong>completely optional</strong> — you can use OpenCode without it.</p><h2 id="background" tabindex="-1">Background <a class="header-anchor" href="#background" aria-label="Permalink to “Background”">​</a></h2><p>There are many models on the market, but only a few work well as coding agents. Additionally, most providers have varying configurations, leading to inconsistent performance and quality.</p><blockquote><p>We&#39;ve tested a set of models that work well with OpenCode.</p></blockquote><p>If you use models through services like OpenRouter, you can&#39;t be sure you&#39;re getting the best version.</p><p>To address this, we&#39;ve done several things:</p><ol><li>Tested a curated set of models and discussed with the team how to run them optimally</li><li>Partnered with several providers to ensure they&#39;re served correctly</li><li>Benchmarked model/provider combinations to produce a recommendation list</li></ol><p>OpenCode Zen is an AI gateway that gives you access to these models.</p><h2 id="how-to-use" tabindex="-1">How to Use <a class="header-anchor" href="#how-to-use" aria-label="Permalink to “How to Use”">​</a></h2>',12)),s(o),t[1]||(t[1]=d('<p>OpenCode Zen works like other providers:</p><ol><li>Log in to the <a href="https://console.opencode.ai" target="_blank" rel="noreferrer">OpenCode Zen Console</a>, add payment information, and copy your API key</li><li>Run the <code>/connect</code> command in the TUI, select OpenCode Zen, and paste your API key</li><li>Run <code>/models</code> in the TUI to see the list of recommended models</li></ol><p>Billing is per-request. You can add credits to your account.</p><h2 id="api-endpoints" tabindex="-1">API Endpoints <a class="header-anchor" href="#api-endpoints" aria-label="Permalink to “API Endpoints”">​</a></h2><p>You can also access models through the following API endpoints:</p><table tabindex="0"><thead><tr><th>Model</th><th>Model ID</th><th>Endpoint</th><th>AI SDK Package</th></tr></thead><tbody><tr><td>GPT 5.2</td><td>gpt-5.2</td><td><code>https://opencode.ai/zen/v1/responses</code></td><td><code>@ai-sdk/openai</code></td></tr><tr><td>GPT 5.1</td><td>gpt-5.1</td><td><code>https://opencode.ai/zen/v1/responses</code></td><td><code>@ai-sdk/openai</code></td></tr><tr><td>GPT 5.1 Codex</td><td>gpt-5.1-codex</td><td><code>https://opencode.ai/zen/v1/responses</code></td><td><code>@ai-sdk/openai</code></td></tr><tr><td>GPT 5.1 Codex Max</td><td>gpt-5.1-codex-max</td><td><code>https://opencode.ai/zen/v1/responses</code></td><td><code>@ai-sdk/openai</code></td></tr><tr><td>GPT 5.1 Codex Mini</td><td>gpt-5.1-codex-mini</td><td><code>https://opencode.ai/zen/v1/responses</code></td><td><code>@ai-sdk/openai</code></td></tr><tr><td>GPT 5</td><td>gpt-5</td><td><code>https://opencode.ai/zen/v1/responses</code></td><td><code>@ai-sdk/openai</code></td></tr><tr><td>GPT 5 Codex</td><td>gpt-5-codex</td><td><code>https://opencode.ai/zen/v1/responses</code></td><td><code>@ai-sdk/openai</code></td></tr><tr><td>GPT 5 Nano</td><td>gpt-5-nano</td><td><code>https://opencode.ai/zen/v1/responses</code></td><td><code>@ai-sdk/openai</code></td></tr><tr><td>Claude Sonnet 4.5</td><td>claude-sonnet-4-5</td><td><code>https://opencode.ai/zen/v1/messages</code></td><td><code>@ai-sdk/anthropic</code></td></tr><tr><td>Claude Sonnet 4</td><td>claude-sonnet-4</td><td><code>https://opencode.ai/zen/v1/messages</code></td><td><code>@ai-sdk/anthropic</code></td></tr><tr><td>Claude Haiku 4.5</td><td>claude-haiku-4-5</td><td><code>https://opencode.ai/zen/v1/messages</code></td><td><code>@ai-sdk/anthropic</code></td></tr><tr><td>Claude Haiku 3.5</td><td>claude-3-5-haiku</td><td><code>https://opencode.ai/zen/v1/messages</code></td><td><code>@ai-sdk/anthropic</code></td></tr><tr><td>Claude Opus 4.5</td><td>claude-opus-4-5</td><td><code>https://opencode.ai/zen/v1/messages</code></td><td><code>@ai-sdk/anthropic</code></td></tr><tr><td>Claude Opus 4.1</td><td>claude-opus-4-1</td><td><code>https://opencode.ai/zen/v1/messages</code></td><td><code>@ai-sdk/anthropic</code></td></tr><tr><td>MiniMax M2.1</td><td>minimax-m2.1-free</td><td><code>https://opencode.ai/zen/v1/messages</code></td><td><code>@ai-sdk/anthropic</code></td></tr><tr><td>Gemini 3 Pro</td><td>gemini-3-pro</td><td><code>https://opencode.ai/zen/v1/models/gemini-3-pro</code></td><td><code>@ai-sdk/google</code></td></tr><tr><td>Gemini 3 Flash</td><td>gemini-3-flash</td><td><code>https://opencode.ai/zen/v1/models/gemini-3-flash</code></td><td><code>@ai-sdk/google</code></td></tr><tr><td>GLM 4.6</td><td>glm-4.6</td><td><code>https://opencode.ai/zen/v1/chat/completions</code></td><td><code>@ai-sdk/openai-compatible</code></td></tr><tr><td>GLM 4.7</td><td>glm-4.7-free</td><td><code>https://opencode.ai/zen/v1/chat/completions</code></td><td><code>@ai-sdk/openai-compatible</code></td></tr><tr><td>Kimi K2</td><td>kimi-k2</td><td><code>https://opencode.ai/zen/v1/chat/completions</code></td><td><code>@ai-sdk/openai-compatible</code></td></tr><tr><td>Kimi K2 Thinking</td><td>kimi-k2-thinking</td><td><code>https://opencode.ai/zen/v1/chat/completions</code></td><td><code>@ai-sdk/openai-compatible</code></td></tr><tr><td>Qwen3 Coder 480B</td><td>qwen3-coder</td><td><code>https://opencode.ai/zen/v1/chat/completions</code></td><td><code>@ai-sdk/openai-compatible</code></td></tr><tr><td>Grok Code Fast 1</td><td>grok-code</td><td><code>https://opencode.ai/zen/v1/chat/completions</code></td><td><code>@ai-sdk/openai-compatible</code></td></tr><tr><td>Big Pickle</td><td>big-pickle</td><td><code>https://opencode.ai/zen/v1/chat/completions</code></td><td><code>@ai-sdk/openai-compatible</code></td></tr></tbody></table><p>Model IDs in OpenCode configuration use the format <code>opencode/&lt;model-id&gt;</code>. For example, GPT 5.1 Codex uses <code>opencode/gpt-5.1-codex</code>.</p><h3 id="getting-the-model-list" tabindex="-1">Getting the Model List <a class="header-anchor" href="#getting-the-model-list" aria-label="Permalink to “Getting the Model List”">​</a></h3><p>Get available models and their metadata:</p>',9)),t[2]||(t[2]=e("div",{class:"language-"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"}),e("pre",null,[e("code",{"v-pre":""},"https://opencode.ai/zen/v1/models")])],-1)),t[3]||(t[3]=d('<h2 id="pricing" tabindex="-1">Pricing <a class="header-anchor" href="#pricing" aria-label="Permalink to “Pricing”">​</a></h2><p>Pay per request. Prices below are <strong>per 1 million tokens</strong>:</p><table tabindex="0"><thead><tr><th>Model</th><th>Input</th><th>Output</th><th>Cache Read</th><th>Cache Write</th></tr></thead><tbody><tr><td>Big Pickle</td><td>Free</td><td>Free</td><td>Free</td><td>-</td></tr><tr><td>Grok Code Fast 1</td><td>Free</td><td>Free</td><td>Free</td><td>-</td></tr><tr><td>MiniMax M2.1</td><td>Free</td><td>Free</td><td>Free</td><td>-</td></tr><tr><td>GLM 4.7</td><td>Free</td><td>Free</td><td>Free</td><td>-</td></tr><tr><td>GLM 4.6</td><td>$0.60</td><td>$2.20</td><td>$0.10</td><td>-</td></tr><tr><td>Kimi K2</td><td>$0.40</td><td>$2.50</td><td>-</td><td>-</td></tr><tr><td>Kimi K2 Thinking</td><td>$0.40</td><td>$2.50</td><td>-</td><td>-</td></tr><tr><td>Qwen3 Coder 480B</td><td>$0.45</td><td>$1.50</td><td>-</td><td>-</td></tr><tr><td>Claude Sonnet 4.5 (≤ 200K tokens)</td><td>$3.00</td><td>$15.00</td><td>$0.30</td><td>$3.75</td></tr><tr><td>Claude Sonnet 4.5 (&gt; 200K tokens)</td><td>$6.00</td><td>$22.50</td><td>$0.60</td><td>$7.50</td></tr><tr><td>Claude Sonnet 4 (≤ 200K tokens)</td><td>$3.00</td><td>$15.00</td><td>$0.30</td><td>$3.75</td></tr><tr><td>Claude Sonnet 4 (&gt; 200K tokens)</td><td>$6.00</td><td>$22.50</td><td>$0.60</td><td>$7.50</td></tr><tr><td>Claude Haiku 4.5</td><td>$1.00</td><td>$5.00</td><td>$0.10</td><td>$1.25</td></tr><tr><td>Claude Haiku 3.5</td><td>$0.80</td><td>$4.00</td><td>$0.08</td><td>$1.00</td></tr><tr><td>Claude Opus 4.5</td><td>$5.00</td><td>$25.00</td><td>$0.50</td><td>$6.25</td></tr><tr><td>Claude Opus 4.1</td><td>$15.00</td><td>$75.00</td><td>$1.50</td><td>$18.75</td></tr><tr><td>Gemini 3 Pro (≤ 200K tokens)</td><td>$2.00</td><td>$12.00</td><td>$0.20</td><td>-</td></tr><tr><td>Gemini 3 Pro (&gt; 200K tokens)</td><td>$4.00</td><td>$18.00</td><td>$0.40</td><td>-</td></tr><tr><td>Gemini 3 Flash</td><td>$0.50</td><td>$3.00</td><td>$0.05</td><td>-</td></tr><tr><td>GPT 5.2</td><td>$1.75</td><td>$14.00</td><td>$0.175</td><td>-</td></tr><tr><td>GPT 5.1</td><td>$1.07</td><td>$8.50</td><td>$0.107</td><td>-</td></tr><tr><td>GPT 5.1 Codex</td><td>$1.07</td><td>$8.50</td><td>$0.107</td><td>-</td></tr><tr><td>GPT 5.1 Codex Max</td><td>$1.25</td><td>$10.00</td><td>$0.125</td><td>-</td></tr><tr><td>GPT 5.1 Codex Mini</td><td>$0.25</td><td>$2.00</td><td>$0.025</td><td>-</td></tr><tr><td>GPT 5</td><td>$1.07</td><td>$8.50</td><td>$0.107</td><td>-</td></tr><tr><td>GPT 5 Codex</td><td>$1.07</td><td>$8.50</td><td>$0.107</td><td>-</td></tr><tr><td>GPT 5 Nano</td><td>Free</td><td>Free</td><td>Free</td><td>-</td></tr></tbody></table><p>You may see <em>Claude Haiku 3.5</em> in your usage history — this is a low-cost model used to generate session titles.</p><blockquote><p>Credit card charges are passed through at cost (4.4% + $0.30 per transaction), we don&#39;t add any extra fees.</p></blockquote><p>Free model notes:</p><ul><li><strong>Grok Code Fast 1</strong>: Free for a limited time, the xAI team is collecting feedback to improve Grok Code</li><li><strong>GLM 4.7</strong>: Free for a limited time, the team is collecting feedback to improve the model</li><li><strong>MiniMax M2.1</strong>: Free for a limited time, the team is collecting feedback to improve the model</li><li><strong>Big Pickle</strong>: Stealth model, free for a limited time, the team is collecting feedback to improve the model</li></ul><h3 id="auto-reload" tabindex="-1">Auto-Reload <a class="header-anchor" href="#auto-reload" aria-label="Permalink to “Auto-Reload”">​</a></h3><p>When your balance falls below $5, Zen will automatically reload $20.</p><p>You can change the auto-reload amount or disable auto-reload entirely.</p><h3 id="monthly-limits" tabindex="-1">Monthly Limits <a class="header-anchor" href="#monthly-limits" aria-label="Permalink to “Monthly Limits”">​</a></h3><p>You can set monthly usage limits for your entire workspace and for each team member.</p><p>For example, if you set a monthly limit of $20, Zen won&#39;t use more than $20 per month. However, if auto-reload is enabled, you may be charged more than $20 when your balance falls below $5.</p><h2 id="privacy" tabindex="-1">Privacy <a class="header-anchor" href="#privacy" aria-label="Permalink to “Privacy”">​</a></h2><p>All models are hosted in the United States. Providers follow a zero-retention policy and don&#39;t use your data for model training, with the following exceptions:</p><ul><li><strong>Grok Code Fast 1</strong>: Data collected during the free period may be used to improve Grok Code</li><li><strong>GLM 4.7</strong>: Data collected during the free period may be used to improve the model</li><li><strong>MiniMax M2.1</strong>: Data collected during the free period may be used to improve the model</li><li><strong>Big Pickle</strong>: Data collected during the free period may be used to improve the model</li><li><strong>OpenAI API</strong>: Requests are retained for 30 days according to <a href="https://platform.openai.com/docs/guides/your-data" target="_blank" rel="noreferrer">OpenAI&#39;s data policy</a></li><li><strong>Anthropic API</strong>: Requests are retained for 30 days according to <a href="https://docs.anthropic.com/en/docs/claude-code/data-usage" target="_blank" rel="noreferrer">Anthropic&#39;s data policy</a></li></ul><h2 id="team-features" tabindex="-1">Team Features <a class="header-anchor" href="#team-features" aria-label="Permalink to “Team Features”">​</a></h2><p>Zen is great for teams. You can invite teammates, assign roles, manage which models your team uses, and more.</p><blockquote><p>Workspace management is free during Beta.</p></blockquote><h3 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to “Roles”">​</a></h3><p>You can invite teammates and assign roles:</p><ul><li><strong>Admin</strong>: Manage models, members, API keys, and billing</li><li><strong>Member</strong>: Can only manage their own API keys</li></ul><p>Admins can also set monthly spending limits for each member.</p><h3 id="model-access-control" tabindex="-1">Model Access Control <a class="header-anchor" href="#model-access-control" aria-label="Permalink to “Model Access Control”">​</a></h3><p>Admins can enable or disable specific models for the workspace. Requests sent to disabled models will return an error.</p><p>This is useful for blocking models that collect data.</p><h3 id="bring-your-own-key" tabindex="-1">Bring Your Own Key <a class="header-anchor" href="#bring-your-own-key" aria-label="Permalink to “Bring Your Own Key”">​</a></h3><p>You can use your own OpenAI or Anthropic API keys while still accessing other models in Zen.</p><p>When using your own keys, tokens are billed directly by the provider, not Zen.</p><p>For example, your organization might already have OpenAI or Anthropic keys and want to use them instead of Zen-provided keys.</p><h2 id="goals" tabindex="-1">Goals <a class="header-anchor" href="#goals" aria-label="Permalink to “Goals”">​</a></h2><p>We created OpenCode Zen to:</p><ol><li><strong>Benchmark</strong> the best models/providers for coding agents</li><li>Provide access to the <strong>highest quality</strong> options without downgrading performance or routing to cheaper providers</li><li><strong>Pass on price reductions</strong> at cost — the only markup is processing fees</li><li>Have <strong>no lock-in</strong>, allowing use with any other coding agent and allowing use of any other provider in OpenCode</li></ol>',33))])}const y=a(l,[["render",c]]);export{b as __pageData,y as default};
